use actix_web::{web, App, HttpServer, HttpRequest, HttpResponse, Error};
use reqwest::Client;
use serde::Deserialize;
use std::time::Duration;

#[derive(Deserialize)]
struct ProxyQuery {
    url: String,
}

async fn proxy_handler(
    req: HttpRequest,
    query: web::Query<ProxyQuery>,
) -> Result<HttpResponse, Error> {
    let target_url = &query.url;

    // Validate the URL
    let parsed_url = match url::Url::parse(target_url) {
        Ok(u) => u,
        Err(_) => {
            return Ok(HttpResponse::BadRequest().body("Invalid URL provided"));
        }
    };

    // Only allow http and https schemes
    match parsed_url.scheme() {
        "http" | "https" => {}
        _ => {
            return Ok(HttpResponse::BadRequest().body("Only HTTP and HTTPS URLs are allowed"));
        }
    }

    let client = Client::builder()
        .timeout(Duration::from_secs(30))
        .redirect(reqwest::redirect::Policy::limited(5))
        .build()
        .map_err(|e| {
            actix_web::error::ErrorInternalServerError(format!("Failed to create HTTP client: {}", e))
        })?;

    // Determine the method to forward
    let method = match req.method().as_str() {
        "GET" => reqwest::Method::GET,
        "POST" => reqwest::Method::POST,
        "PUT" => reqwest::Method::PUT,
        "DELETE" => reqwest::Method::DELETE,
        "PATCH" => reqwest::Method::PATCH,
        "HEAD" => reqwest::Method::HEAD,
        "OPTIONS" => reqwest::Method::OPTIONS,
        _ => {
            return Ok(HttpResponse::MethodNotAllowed().body("Unsupported HTTP method"));
        }
    };

    // Build the outgoing request
    let mut outgoing_request = client.request(method, target_url);

    // Forward relevant headers from the incoming request
    let headers_to_forward = ["content-type", "accept", "authorization", "user-agent", "x-request-id"];
    for header_name in &headers_to_forward {
        if let Some(value) = req.headers().get(*header_name) {
            if let Ok(header_name_parsed) = reqwest::header::HeaderName::from_bytes(header_name.as_bytes()) {
                if let Ok(header_value) = reqwest::header::HeaderValue::from_bytes(value.as_bytes()) {
                    outgoing_request = outgoing_request.header(header_name_parsed, header_value);
                }
            }
        }
    }

    // Send the request
    let response = outgoing_request.send().await.map_err(|e| {
        actix_web::error::ErrorBadGateway(format!("Failed to fetch URL: {}", e))
    })?;

    // Build the response to return
    let status = actix_web::http::StatusCode::from_u16(response.status().as_u16())
        .unwrap_or(actix_web::http::StatusCode::INTERNAL_SERVER_ERROR);

    let mut http_response = HttpResponse::build(status);

    // Forward response headers
    for (name, value) in response.headers().iter() {
        let header_name_str = name.as_str();
        // Skip hop-by-hop headers and transfer-encoding
        if matches!(
            header_name_str,
            "transfer-encoding" | "connection" | "keep-alive" | "proxy-authenticate"
                | "proxy-authorization" | "te" | "trailers" | "upgrade"
        ) {
            continue;
        }
        if let Ok(actix_name) = actix_web::http::header::HeaderName::from_bytes(name.as_str().as_bytes()) {
            if let Ok(actix_value) = actix_web::http::header::HeaderValue::from_bytes(value.as_bytes()) {
                http_response.insert_header((actix_name, actix_value));
            }
        }
    }

    let body = response.bytes().await.map_err(|e| {
        actix_web::error::ErrorBadGateway(format!("Failed to read response body: {}", e))
    })?;

    Ok(http_response.body(body))
}

